import { useEffect, useState } from 'react';

import { useKeyboardSelectionShortcuts } from './useKeyboardSelectionShortcuts.js';
import { LegendItem } from '../types/legend.js';

interface LegendInteractionsCallbacks {
  onHover?: (_: LegendItem | undefined) => void;
  onClick?: (_: LegendItem[]) => void;
}

export const useLegendInteractions = (
  items: LegendItem[],
  callbacks: LegendInteractionsCallbacks,
) => {
  const [hiddenItems, setHiddenItems] = useState<Set<string>>(
    new Set<string>([]),
  );

  useEffect(() => {
    setHiddenItems(new Set<string>([]));
  }, [items]);

  const { onHover, onClick } = callbacks;
  const selectItem = useKeyboardSelectionShortcuts(items);

  const onLegendIconClick = (item: LegendItem) => {
    if (hiddenItems.has(item.id)) {
      hiddenItems.delete(item.id);
    } else {
      hiddenItems.add(item.id);
    }

    // remove highlighted series
    onHover?.(undefined);
    setHiddenItems(hiddenItems);
    onClick?.(items.filter((i) => !hiddenItems.has(i.id)));
  };

  const onItemHover = (item?: LegendItem) => {
    onHover?.(item);
  };

  const onLegendNameClick = (item: LegendItem, event: MouseEvent) => {
    const newSelection = selectItem(item, hiddenItems, event);
    const newHiddenItems = items
      .filter((item) => !newSelection.includes(item))
      .map((i) => i.id);

    setHiddenItems(new Set(newHiddenItems));
    onClick?.(newSelection);
  };

  return { onLegendIconClick, onItemHover, onLegendNameClick, hiddenItems };
};
